import java.sql.*;

public class SQLInjectionSecure {
    public static void main(String[] args) {
        try {
            // Get user input (this should come from user input)
            String userInput = "admin'; DROP TABLE users; --";

            // Create a connection to a SQLite database
            Connection conn = DriverManager.getConnection("jdbc:sqlite:test.db");

            // Create a parameterized SQL query
            String query = "SELECT * FROM users WHERE username=?";

            // Prepare the statement with the parameterized query
            PreparedStatement pstmt = conn.prepareStatement(query);

            // Set the parameter value safely
            pstmt.setString(1, userInput);

            // Execute the query using prepared statement
            ResultSet rs = pstmt.executeQuery();

            // Process the results
            while (rs.next()) {
                System.out.println("User found: " + rs.getString("username"));
            }

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

